/** Build a display string from structured location fields */
export function displayLocation(a: { city?: string | null; state?: string | null; country?: string | null }): string {
  if (a.city && a.state) return `${a.city}, ${a.state}`;
  if (a.state) {
    const name = STATE_ABBR_TO_NAME.get(a.state);
    return name || a.state;
  }
  if (a.city && a.country) return `${a.city}, ${a.country}`;
  if (a.country && a.country !== "US") return COUNTRY_DISPLAY[a.country] || a.country;
  return "US";
}

const COUNTRY_DISPLAY: Record<string, string> = {
  AU: "Australia", IT: "Italy", UK: "UK", DE: "Germany", ES: "Spain",
  FR: "France", RU: "Russia", UA: "Ukraine", BR: "Brazil", KR: "South Korea",
  CA: "Canada", EU: "Europe", INTL: "International",
};

const INTL_COUNTRY_CODES = ["AU","IT","UK","DE","ES","FR","RU","UA","BR","KR","CA","EU","INTL"];

/** Match artist location against a filter value from RegionPicker */
export function locationMatchesFilter(a: Artist, filter: string): boolean {
  if (!filter) return true;

  // Check if filter is a US state name
  const stateAbbr = STATE_NAME_TO_ABBR.get(filter);
  if (stateAbbr) {
    return (a.state || "").toUpperCase() === stateAbbr;
  }

  // International matching
  const country = (a.country || "").toUpperCase();
  switch (filter) {
    case "Australia": return country === "AU";
    case "UK": return country === "UK";
    case "Italy": return country === "IT";
    case "Germany": return country === "DE";
    case "Spain": return country === "ES";
    case "France": return country === "FR";
    case "Russia": return country === "RU";
    case "Ukraine": return country === "UA";
    case "Brazil": return country === "BR";
    case "South Korea": return country === "KR";
    case "Canada": return country === "CA";
    case "Other Europe": return country === "EU";
    case "Other Intl": return country === "INTL";
    default:
      return (a.city || "").toLowerCase() === filter.toLowerCase() ||
             (a.country || "").toLowerCase() === filter.toLowerCase();
  }
}

/** Derive price range (1-5) from artist data; manual override wins, default 4 */
export const getPriceRange = (a: Artist): number => {
  if (a.price_tier && a.price_tier >= 1 && a.price_tier <= 5) return a.price_tier;
  if (a.rating >= 5.0 || (a.rating >= 4.9 && a.pieces >= 350)) return 5;
  return 4;
};

export const priceLabel = (n: number) => "$".repeat(n);

