export function deriveRegion(region: string, bio: string, artistId?: number): string {
  // 1. California sub-regions
  if (region === "California") {
    if (bio.includes("San Diego") || bio.includes("619")) return "San Diego, CA";
    if (bio.includes("Sacramento")) return "Sacramento, CA";
    if (bio.includes("Central Coast")) return "Ventura, CA";
    if (bio.includes("San Francisco") || bio.includes("Bay Area")) return "San Francisco, CA";
    return "Los Angeles, CA";
  }

  // 3. US - Other: scan bio for city keywords
  if (region === "US - Other") {
    for (const [kw, st] of US_CITY_KW) {
      if (bio.includes(kw)) {
        return `${kw}, ${st}`;
      }
    }
    // If no city match, still mark as generic US
    return "US - Other";
  }

  // 4. Europe / International: scan for country keywords
  if (region === "Europe" || region === "International") {
    for (const [kw, country] of COUNTRY_KW) {
      if (bio.includes(kw)) return country;
    }
  }

  // 5. Australia sub-regions
  if (region === "Australia") {
    if (bio.includes("Sydney")) return "Sydney, AU";
    if (bio.includes("Melbourne")) return "Melbourne, AU";
    return "Australia";
  }

  return region;
}

