// Transform static data: derive city/state/country from legacy region field
function deriveLocationFromRegion(rawRegion: string, bio: string, _id?: number): { city?: string; state?: string; country?: string } {
  if (rawRegion === "California") {
    if (bio.includes("San Diego") || bio.includes("619")) return { city: "San Diego", state: "CA", country: "US" };
    if (bio.includes("Sacramento")) return { city: "Sacramento", state: "CA", country: "US" };
    if (bio.includes("Central Coast")) return { city: "Ventura", state: "CA", country: "US" };
    if (bio.includes("San Francisco") || bio.includes("Bay Area")) return { city: "San Francisco", state: "CA", country: "US" };
    if (bio.includes("Anaheim")) return { city: "Anaheim", state: "CA", country: "US" };
    return { city: "Los Angeles", state: "CA", country: "US" };
  }
  if (rawRegion === "US - Other") {
    for (const [kw, st] of US_CITY_KW) {
      if (bio.includes(kw)) return { city: kw, state: st, country: "US" };
    }
    return { country: "US" };
  }
  if (rawRegion === "Australia") {
    if (bio.includes("Sydney")) return { city: "Sydney", country: "AU" };
    if (bio.includes("Melbourne")) return { city: "Melbourne", country: "AU" };
    return { country: "AU" };
  }
  if (rawRegion === "Europe") {
    for (const [kw, c] of COUNTRY_KW) { if (bio.includes(kw)) return { country: c === "UK" ? "UK" : "EU" }; }
    return { country: "EU" };
  }
  if (rawRegion === "International") {
    for (const [kw, c] of COUNTRY_KW) { if (bio.includes(kw)) return { country: "INTL" }; }
    return { country: "INTL" };
  }
  return {};
}

export const ARTISTS: Artist[] = _RAW.map(a => {
  const loc = deriveLocationFromRegion((a as any).region || "", a.bio, a.id);
  const { region: _r, ...rest } = a as any;
  return { ...rest, city: loc.city || null, state: loc.state || null, country: loc.country || "US" } as Artist;
});

export const getSimilar = (artist: Artist): Artist[] =>
  ARTISTS.filter(a => a.id !== artist.id && a.styles.some(s => artist.styles.includes(s)))
    .sort((a, b) => {
      const as2 = a.styles.filter(s => artist.styles.includes(s)).length;
      const bs2 = b.styles.filter(s => artist.styles.includes(s)).length;
      return bs2 - as2 || b.rating - a.rating;
    })
    .slice(0, 4);
